INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.12.215','cb','cb.adi.12','ЧБ Ади 12.215',215,'দেখি’ প্রভু পৌর্ণমাসী-চন্দ্রের উদয় ।
বৃন্দাবনচন্দ্র-ভাব হইল হৃদয় ॥২১৫॥','декхи’ прабху паурн̣ама̄сӣ-чандрера удайа
вр̣нда̄вана-чандра-бха̄ва хаила хр̣дайа',NULL,NULL),('cb.adi.12.216','cb','cb.adi.12','ЧБ Ади 12.216',216,'অপূর্ব্ব মুরলী-ধ্বনি লাগিলা করিতে ।
আই বই আর কেহ না পায় শুনিতে ॥২১৬॥','апӯрва муралӣ-дхвани ла̄гила̄ карите
а̄и баи а̄ра кеха на̄ па̄йа ш́уните',NULL,NULL),('cb.adi.12.217','cb','cb.adi.12','ЧБ Ади 12.217',217,'ত্রিভুবন-মোহন মুরলী শুনি’ আই ।
আনন্দ-মগনে মূর্চ্ছা গেলা সেই ঠাঞি ॥২১৭॥','трибхувана-мохана муралӣ ш́уни’ а̄и
а̄нанда-магане мӯрчха̄ гела̄ сеи т̣ха̄н̃и',NULL,NULL),('cb.adi.12.218','cb','cb.adi.12','ЧБ Ади 12.218',218,'ক্ষণেকে চৈতন্য পাই’ স্থির করি’ মন ।
অপূর্ব্ব মুরলী-ধ্বনি করেন শ্রবণ ॥২১৮॥','кш̣ан̣еке чаитанйа па̄и’ стхира кари’ мана
апӯрва муралӣ-дхвани карена ш́раван̣а',NULL,NULL),('cb.adi.12.219','cb','cb.adi.12','ЧБ Ади 12.219',219,'যেখানে বসিয়া আছে গৌরাঙ্গসুন্দর ।
সেইদিকে শুনিলেন বংশী মনোহর ॥২১৯॥','йекха̄не васийа̄ а̄чхе гаура̄н̇га-сундара
сеи-дике ш́унилена вам̇ш́ӣ манохара',NULL,NULL),('cb.adi.12.220','cb','cb.adi.12','ЧБ Ади 12.220',220,'অদ্ভুত শুনিয়া আই আইলা বাহিরে ।
দেখে,—পুত্ত্র বসিয়াছে বিষ্ণুর দুয়ারে ॥২২০॥','адбхута ш́унийа̄ а̄и а̄ила̄ ба̄хире
декхе, — путра васийа̄чхе виш̣н̣ира дуйа̄ре',NULL,NULL),('cb.adi.12.221','cb','cb.adi.12','ЧБ Ади 12.221',221,'আর নাহি পায়েন শুনিতে বংশীনাদ ।
পুত্ত্রের হৃদয়ে দেখে আকাশের চাঁদ ॥২২১॥','а̄ра на̄хи па̄йена ш́уните вам̇ш́ӣ-на̄да
путрера хр̣дайе декхе а̄ка̄ш́ера ча̄н̇да',NULL,NULL),('cb.adi.12.222','cb','cb.adi.12','ЧБ Ади 12.222',222,'পুত্ত্র-বক্ষে দেখে চন্দ্রমণ্ডল সাক্ষাতে ।
বিস্মিত হইয়া আই চা’হে চারিভিতে ॥২২২॥','путра-вакш̣е декхе чандра-ман̣д̣ала са̄кш̣а̄те
висмита хаийа̄ а̄и ча̄хе ча̄ри-бхите',NULL,NULL),('cb.adi.12.223','cb','cb.adi.12','ЧБ Ади 12.223',223,'গৃহে আসি’ বসি’ আই লাগিলা চিন্তিতে ।
কি হেতু,—নিশ্চয় কিছু না পারে করিতে ॥২২৩॥','гр̣хе а̄си’ васи’ а̄и ла̄гила̄ чинтите
ки хету, — ниш́чайа кичху на̄ па̄ре карите',NULL,NULL),('cb.adi.12.224','cb','cb.adi.12','ЧБ Ади 12.224',224,'এইমত কত ভাগ্যবতী শচী আই ।
যত দেখে প্রকাশ, তাহার অন্ত নাই ॥২২৪॥','эи-мата ката бха̄гйаватӣ ш́ачӣ а̄и
йата декхе прака̄ш́а, та̄ха̄ра анта на̄и',NULL,NULL),('cb.adi.12.225','cb','cb.adi.12','ЧБ Ади 12.225',225,'কোনদিন নিশাভাগে শচী আই শুনে ।
গীত, বাদ্য-যন্ত্র বা’য় কতশত জনে ॥২২৫॥','кона-дина ниш́а̄-бха̄ге ш́ачӣ а̄и ш́уне
гӣта, ва̄дйа-йантра ва̄йа ката-ш́ата джане',NULL,NULL),('cb.adi.12.226','cb','cb.adi.12','ЧБ Ади 12.226',226,'বহুবিধ মুখবাদ্য, নৃত্য, পদতাল ।
যেন মহা-রাসক্রীড়া শুনেন বিশাল ॥২২৬॥','баху-видха мукха-ва̄дйа, нр̣тйа, пада-та̄ла
йена маха̄-ра̄са-крӣд̣а̄ ш́унена виш́а̄ла',NULL,NULL),('cb.adi.12.227','cb','cb.adi.12','ЧБ Ади 12.227',227,'কোনদিন দেখে সর্ব্ব-বাড়ী ঘর-দ্বার ।
জ্যোতির্ম্ময় বই কিছু না দেখেন আর ॥২২৭॥','кона-дина декхе сарва ба̄д̣ӣ-гхара-два̄ра
джйотир-майа баи кичху на̄ декхена а̄ра',NULL,NULL),('cb.adi.12.228','cb','cb.adi.12','ЧБ Ади 12.228',228,'কোনদিন দেখে অতি-দিব্য নারীগণ ।
লক্ষ্মী-প্রায় সবে, হস্তে পদ্ম-বিভূষণ ॥২২৮॥','кона-дина декхе ати-дивйа на̄рӣ-ган̣а
лакш̣мӣ-пра̄йа сабе, хасте падма-вибхӯш̣ан̣а',NULL,NULL),('cb.adi.12.229','cb','cb.adi.12','ЧБ Ади 12.229',229,'কোনদিন দেখে জ্যোতির্ম্ময় দেবগণ ।
দেখি’ পুনঃ আর নাহি পায় দরশন ॥২২৯॥','кона-дина декхе джйотир-майа дева-ган̣а
декхи’ пунах̣ а̄ра на̄хи па̄йа дараш́ана',NULL,NULL),('cb.adi.12.230','cb','cb.adi.12','ЧБ Ади 12.230',230,'আইর এ-সব দৃষ্টি কিছু চিত্র নহে ।
বিষ্ণুভক্তিস্বরূপিণী বেদে যাঁরে কহে ॥২৩০॥','а̄ира э-саба др̣ш̣т̣и кичху читра нахе
виш̣н̣у-бхакти-сварӯпин̣ӣ веде йа̄н̇’ ре кахе',NULL,NULL),('cb.adi.12.231','cb','cb.adi.12','ЧБ Ади 12.231',231,'আই যারে সকৃৎ করেন দৃষ্টিপাতে ।
সেই হয় অধিকারী এ সব দেখিতে ॥২৩১॥','а̄и йа̄’ре сакр̣т карена др̣ш̣т̣и-па̄те
сеи хайа адхика̄рӣ э саба декхите',NULL,NULL),('cb.adi.12.232','cb','cb.adi.12','ЧБ Ади 12.232',232,'হেনমতে শ্রীগৌরসুন্দর বনমালী ।
আছে গূঢ়রূপে নিজানন্দে কুতূহলী ॥২৩২॥','хӣна-мате ш́рӣ-гаурасундара ванама̄лӣ
а̄чхе гӯд̣ха-рӯпе ниджа̄нанде кутухалӣ',NULL,NULL),('cb.adi.12.233','cb','cb.adi.12','ЧБ Ади 12.233',233,'যদ্যপি এতেক প্রভু আপনা’ প্রকাশে ।
তথাপিহ চিনিতে না পারে কোন দাসে ॥২৩৩॥','йадйапи этека прабху а̄пана̄’ прака̄ш́е
татха̄пиха чините на̄ па̄ре кона да̄се',NULL,NULL),('cb.adi.12.234','cb','cb.adi.12','ЧБ Ади 12.234',234,'হেন সে ঔদ্ধত্য প্রভু করেন কৌতুকে ।
তেমত উদ্ধত আর নাহি নবদ্বীপে ॥২৩৪॥
যখন যেরূপে লীলা করেন ঈশ্বর ।
সেই সর্ব্ব-শ্রেষ্ঠ, তার নাহিক সোসর ॥২৩৫॥
যুদ্ধ-লীলা-প্রতি ইচ্ছা উপজে যখন ।
অস্ত্র-শিক্ষা-বীর আর না থাকে তেমন ॥২৩৬॥
কাম-লীলা করিতে যখন ইচ্ছা হয় ।
লক্ষার্ব্বুদ বনিতা সে করেন বিজয় ॥২৩৭॥
ধন বিলসিতে সে যখন ইচ্ছা হয় ।
প্রজার ঘরেতে হয় নিধি কোটিময় ॥২৩৮॥
এমন উদ্ধত গৌরসুন্দর এখনে ।
এই প্রভু বিরক্ত-ধর্ম্ম লইবে যখনে ॥২৩৯॥
সে বিরক্তি-ভক্তি-কণা কোথা ত্রিভুবনে? ।
অন্যে কি সম্ভবে তাহা ?—ব্যক্ত সর্ব্বজনে ॥২৪০॥','хӣна се ауддхатйа прабху карена каутуке
те-мата уддхата а̄ра на̄хи навадвӣпе
йакхана йе-рӯпе лӣла̄ карена ӣш́вара
сеи сарва-ш́рӣш̣т̣ха, та̄’ра на̄хика сосара
йуддха лӣла̄-прати иччха̄ упадже йакхана
астра-сикш̣а̄-вӣра а̄ра на̄ тха̄ке темана
ка̄ма-лӣла̄ карите йакхана иччха̄ хайа
лакш̣а̄рбуда ванита̄ се карена виджайа
дхана виласите се йакхана иччха̄ хайа
праджа̄ра гхарете хайа нидхи кот̣и-майа
се виракти-бхакти-кан̣а̄ котха̄ трибхуване?
анйе ки самбхаве та̄ха̄? — вйакта сарва джане',NULL,NULL),('cb.adi.12.241','cb','cb.adi.12','ЧБ Ади 12.241',241,'এইমত ঈশ্বরের সর্ব্বশ্রেষ্ঠ কর্ম্ম ।
সবে সেবকেরে হারে, সে তাহান ধর্ম্ম ॥২৪১॥','эи-мата ӣш́варера сарва-ш́рӣш̣т̣ха-карма
сабе севакере ха̄рӣ, се та̄ха̄на дхарма',NULL,NULL),('cb.adi.12.242','cb','cb.adi.12','ЧБ Ади 12.242',242,'একদিন প্রভু আইসেন রাজ-পথে ।
পাঁচ সাত পড়ুয়া প্রভুর চারিভিতে ॥২৪২॥','эка-дина прабху а̄исена ра̄джа-патхе
па̄н̃ча са̄та пад̣уйа̄ прабхура са̄ри-бхите',NULL,NULL),('cb.adi.12.243','cb','cb.adi.12','ЧБ Ади 12.243',243,'ব্যবহারে রাজযোগ্য বস্ত্র পরিধান ।
অঙ্গে পীতবস্ত্র শোভে কৃষ্ণের সমান ॥২৪৩॥','вйаваха̄ре ра̄джа-йогйа вастра паридха̄на
ан̇ге пӣта-вастра ш́обхе кр̣ш̣н̣ера сама̄на',NULL,NULL),('cb.adi.12.244','cb','cb.adi.12','ЧБ Ади 12.244',244,'অধরে তাম্বূল, কোটি-চন্দ্র শ্রীবদন ।
লোকে বোলে,—“মূর্ত্তিমন্ত এই কি মদন?” ॥২৪৪॥','адхаре та̄мбӯла, кот̣и-чандра ш́рӣ-вадана
локе боле, — ‘мӯрти-манта эи ки мадана?’',NULL,NULL),('cb.adi.12.245','cb','cb.adi.12','ЧБ Ади 12.245',245,'ললাটে তিলক-ঊর্দ্ধ, পুস্তক শ্রীকরে ।
দৃষ্টিমাত্রে পদ্মনেত্রে সর্ব্ব-পাপ হবে’ ॥২৪৫॥','лала̄т̣е тилака-ӯрддхва, пустака ш́рӣ-каре
др̣ш̣т̣и-ма̄тре падма-нетре сарва-па̄па харе’',NULL,NULL),('cb.adi.12.246','cb','cb.adi.12','ЧБ Ади 12.246',246,'স্বভাবে চঞ্চল পড়ুয়ার বর্গ-সঙ্গে ।
বাহু দোলাইয়া প্রভু আইসেন রঙ্গে ॥২৪৬॥','свабха̄ве чан̃чала пад̣уйа̄ра варга-сан̇ге
ба̄ху дола̄ийа̄ прабху а̄исена ран̇ге',NULL,NULL),('cb.adi.12.247','cb','cb.adi.12','ЧБ Ади 12.247',247,'দৈবে পথে আইসেন পণ্ডিত শ্রীবাস ।
প্রভু দেখি’ মাত্র তান হৈল মহা-হাস ॥২৪৭॥','даиве патхе а̄исена пан̣д̣ита ш́рӣва̄са
прабху декхи’ ма̄тра та̄’на хаила маха̄-ха̄са',NULL,NULL),('cb.adi.12.248','cb','cb.adi.12','ЧБ Ади 12.248',248,'তানে দেখি’ প্রভু করিলেন নমস্কার ।
“চিরজীবী হও”, বোলে শ্রীবাস উদার ॥২৪৮॥','та̄’не декхи’ прабху карилена намаска̄ра
‘чираджӣвӣ хао’ боле ш́рӣва̄са уда̄ра',NULL,NULL),('cb.adi.12.254','cb','cb.adi.12','ЧБ Ади 12.254',254,'এত বলি’ মহাপ্রভু হাসিয়া চলিলা ।
গঙ্গাতীরে আসি’ শিষ্য-সহিতে মিলিলা ॥২৫৪॥','эта бали’ маха̄прабху ха̄сийа̄ чалила̄
ган̇га̄-тӣре а̄си’ ш́иш̣йа-сахите милила̄',NULL,NULL),('cb.adi.12.255','cb','cb.adi.12','ЧБ Ади 12.255',255,'গঙ্গাতীরে বসিলেন শ্রীশচীনন্দন ।
চতুর্দ্দিকে বেড়িয়া বসিলা শিষ্যগণ ॥২৫৫॥','ган̇га̄-тӣре василена ш́рӣ-ш́ачӣнандана
чатур-дике вед̣ийа̄ васила̄ ш́иш̣йа-ган̣а',NULL,NULL),('cb.adi.12.256','cb','cb.adi.12','ЧБ Ади 12.256',256,'কোটি-মুখে সেই শোভা না পারি কহিতে ।
উপমাও তার নাহি দেখি ত্রিজগতে ॥২৫৬॥','кот̣и-мукхе сеи ш́обха̄ на̄ па̄ри кахите
упама̄ о та̄’ра на̄хи декхи триджагате',NULL,NULL),('cb.adi.12.257','cb','cb.adi.12','ЧБ Ади 12.257',257,'চন্দ্র-তারাগণ বা বলিব, সেহো নয় ।
সকলঙ্ক,—তার কলা-ক্ষয়-বৃদ্ধি হয় ॥২৫৭॥','чандра-та̄ра̄-ган̣а ва̄ балиба, сехо найа
сакалан̇ка, — ‘та̄’ра кала̄ кш̣айа-вр̣ддхи хайа',NULL,NULL),('cb.adi.12.258','cb','cb.adi.12','ЧБ Ади 12.258',258,'সর্ব্ব-কাল-পরিপূর্ণ এ প্রভুর কলা ।
নিষ্কলঙ্ক, তেঞি সে উপমা দূরে গেলা ॥২৫৮॥','сарва-ка̄ла-парипӯрн̣а э прабхура кала̄
ниш̣калан̇ка, тен̃и се упама̄ дӯре гела̄',NULL,NULL),('cb.adi.12.259','cb','cb.adi.12','ЧБ Ади 12.259',259,'বৃহস্পতি-উপমাও দিতে না যুয়ায় ।
তেঁহো একপক্ষ,—দেবগণের সহায় ॥২৫৯॥','бр̣хаспати-упама̄ о дите на̄ йуйа̄йа
тен̇хо эка-пакш̣а, — дева-ган̣ера саха̄йа',NULL,NULL),('cb.adi.12.260','cb','cb.adi.12','ЧБ Ади 12.260',260,'এ প্রভু—সবার পক্ষ, সহায় সবার ।
অতএব সে দৃষ্টান্ত না হয় ইঁহার ॥২৬০॥','э прабху—саба̄ра пакш̣а, саха̄йа саба̄ра
атаева се др̣ш̣т̣а̄нта на̄ хайа ин̇ха̄ра',NULL,NULL),('cb.adi.12.261','cb','cb.adi.12','ЧБ Ади 12.261',261,'কামদেব-উপমা বা দিব, সেহো নয় ।
তেঁহো চিত্তে জাগিলে, চিত্তের ক্ষোভ হয় ॥২৬১॥','ка̄мадева-упама̄ ва̄ диба, сехо найа
тен̇хо читте джа̄гиле, читтера кш̣обха хайа',NULL,NULL),('cb.adi.12.262','cb','cb.adi.12','ЧБ Ади 12.262',262,'এ প্রভু জাগিলে চিত্তে, সর্ব্ববন্ধ-ক্ষয় ।
পরম-নির্ম্মল সুপ্রসন্ন চিত্ত হয় ॥২৬২॥','э прабху джа̄гиле читте
сарва-бандха-кш̣айа',NULL,NULL),('cb.adi.12.263','cb','cb.adi.12','ЧБ Ади 12.263',263,'এইমত সকল দৃষ্টান্ত যোগ্য নয় ।
সবে এক উপমা দেখিয়া চিত্তে লয় ॥২৬৩॥
কালিন্দীর তীরে যেন শ্রীনন্দকুমার ।
গোপবৃন্দ-মধ্যে বসি’ করিলা বিহার ॥২৬৪॥
সেই গোপবৃন্দ লই’ সেই কৃষ্ণচন্দ্র ।
বুঝি,—দ্বিজরূপে গঙ্গাতীরে করে রঙ্গ ॥২৬৫॥','эи-мата сакала др̣ш̣т̣а̄нта йогйа найа
сабе эка упама̄ декхийа̄ читте лайа
ка̄линдӣра тӣре йена ш́рӣ-нанда-кума̄ра
гопа-вр̣нда-мадхйе васи’ карила̄ виха̄ра
сеи гопа-вр̣нда лаи’ сеи кр̣ш̣н̣ачандра
буджхи,— двиджа-рӯпе ган̇га̄-тӣре каре ран̇га',NULL,NULL),('cb.adi.12.266','cb','cb.adi.12','ЧБ Ади 12.266',266,'গঙ্গাতীরে যে-যে-জনে দেখে প্রভু-মুখ ।
সেই পায় অতি-অনির্ব্বচনীয় সুখ ॥২৬৬॥
দেখিয়া প্রভুর তেজ অতি-বিলক্ষণ ।
গঙ্গাতীরে কাণাকানি করে সর্ব্বজন ॥২৬৭॥
কেহ বোলে,—“এত তেজ মানুষের নয়” ।
কেহ বোলে,—“এ ব্রাহ্মণ বিষ্ণু-অংশ হয়” ॥২৬৮॥
কেহ বোলে,—“বিপ্র রাজা হইবেক গৌড়ে ।
সেহ এই বুঝি,—এই কথন না নড়ে ॥২৬৯॥
রাজ-চক্রবর্ত্তী-চিহ্ন দেখিয়ে সকল” ।
এইমত বোলে যার যত বুদ্ধি-বল ॥২৭০॥','ган̇га̄-тӣре йе-йе-джане декхе прабху-мукха
сеи па̄йа ати-анирвачанӣйа сукха
декхийа̄ прабхура теджа ати-вилакш̣ан̣а
ган̇га̄-тӣре ка̄н̣а̄ка̄н̣и каре сарва-джана
кеха боле, — ‘ета теджа ма̄нуш̣ера найа’
кеха боле, — ‘е бра̄хман̣а виш̣н̣у-ам̇ш́а хайа’
кеха боле, — ‘випра ра̄джа̄ хаибека гауд̣е
сеи эи буджхи, — эи катхана на̄ над̣е
ра̄джа-чакравартӣ-чихна декхийе сакала’
эи-мата боле йа̄’ра йата буддхи-бала',NULL,NULL),('cb.adi.12.271','cb','cb.adi.12','ЧБ Ади 12.271',271,'অধ্যাপক-প্রতি সব কটাক্ষ করিয়া ।
ব্যাখ্যা করে প্রভু গঙ্গাসমীপে বসিয়া ॥২৭১॥','адхйа̄пака-прати саба кат̣а̄кш̣а̄ карийа̄
